<template>
    <div class="card card-collapsed">
        <div class="card-header bg-primary">
            <h6 class="my-0 text-white">
                Tipos de comprobantes
                <el-tooltip
                    class="item"
                    effect="dark"
                    content="Ingresos"
                    placement="top-start"
                >
                    <i class="fa fa-info-circle"></i>
                </el-tooltip>
            </h6>
            <div class="card-actions white-text">
                <a
                    href="#"
                    class="card-action card-action-toggle text-white"
                    data-card-toggle=""
                ></a>
                <a
                    href="#"
                    class="card-action card-action-dismiss text-white"
                    data-card-dismiss=""
                ></a>
            </div>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col">
                    <button
                        type="button"
                        class="btn btn-custom btn-sm  mt-2 mr-2"
                        @click.prevent="clickCreate()"
                    >
                        <i class="fa fa-plus-circle"></i> Nuevo
                    </button>
                </div>
            </div>
            <div class="table-responsive">
                <table class="table">
                    <thead>
                        <tr>
                            <th>#</th>
                            <th>Descripción</th>
                            <th class="text-end">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr v-for="(row, index) in records" :key="index">
                            <td>{{ index + 1 }}</td>
                            <td>{{ row.description }}</td>
                            <td class="text-end">
                                <button
                                    type="button"
                                    class="btn waves-effect waves-light btn-sm btn-info"
                                    @click.prevent="clickCreate(row.id)"
                                >
                                    Editar
                                </button>
                                <template v-if="row.id != 1">
                                    <template
                                        v-if="
                                            typeUser === 'admin' ||
                                                typeUser === 'superadmin'
                                        "
                                    >
                                        <button
                                            type="button"
                                            class="btn waves-effect waves-light btn-sm btn-danger"
                                            @click.prevent="clickDelete(row.id)"
                                        >
                                            Eliminar
                                        </button>
                                    </template>
                                </template>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            <!-- <div class="row">
                <div class="col">
                    <button type="button" class="btn btn-custom btn-sm  mt-2 mr-2" @click.prevent="clickCreate()"><i class="fa fa-plus-circle"></i> Nuevo</button>
                </div>
            </div> -->
        </div>
        <income-types-form
            :showDialog.sync="showDialog"
            :recordId="recordId"
        ></income-types-form>
    </div>
</template>

<script>
import IncomeTypesForm from "./form.vue";
import { deletable } from "@mixins/deletable";

export default {
    mixins: [deletable],
    props: ["typeUser"],
    components: { IncomeTypesForm },
    data() {
        return {
            showDialog: false,
            resource: "income-types",
            recordId: null,
            records: []
        };
    },
    created() {
        this.$eventHub.$on("reloadData", () => {
            this.getData();
        });
        this.getData();
    },
    methods: {
        getData() {
            this.$http.get(`/${this.resource}/records`).then(response => {
                this.records = response.data.data;
            });
        },
        clickCreate(recordId = null) {
            this.recordId = recordId;
            this.showDialog = true;
        },
        clickDelete(id) {
            this.destroy(`/${this.resource}/${id}`).then(() =>
                this.$eventHub.$emit("reloadData")
            );
        }
    }
};
</script>



